final:
module RefModule (  
    input clk,  
    input reset,  
    input shift_enable,  
    input serial_in,  
    output reg [15:0] parallel_out  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            parallel_out <= 16'b0;  
        else if (shift_enable)  
            parallel_out <= {parallel_out[14:0], serial_in};  
    end  
endmodule
